The existing Ministral 3 specialized handler also has `[INST]/[/INST]` in its template, but
it additionally contains `[SYSTEM_PROMPT]`. The new handler must guard on the _absence_ of
`[SYSTEM_PROMPT]` to avoid matching Ministral 3 templates.

The user requires: **only add new code — do not modify any existing handlers or chat.h**.

---

## Critical Files

| File | Role |
|------|------|
| `common/chat.cpp` | Add handler function + detection entry |
| `models/templates/mistralai-Mistral-Nemo-Instruct-2407.jinja` | Reference template (read-only) |
| `common/chat-peg-parser.h` | PEG builder API (read-only reference) |
| `common/chat.h` | Types / `common_chat_template` API (do NOT touch) |

---

## Implementation Steps

### Step 1 — Add the handler function in `common/chat.cpp`

Insert a new static function **immediately before** the `common_chat_try_specialized_template`
function (i.e., after the closing brace of `common_chat_params_init_gigachat_v3` at line ~1517,
and before the `namespace workaround` block — or after `common_chat_extra_context`, whichever
keeps related handlers together). A natural location is just before line 1634 where
`common_chat_try_specialized_template` starts.

```cpp
// Mistral Instruct v0.3 format
// - User turns:       [INST]{content}[/INST]
// - System message:   prepended to the first user turn inside [INST]...[/INST]
// - Assistant turns:  {content}</s>
// - Tool calls:       [TOOL_CALLS][{"name":"fn","arguments":{...},"id":"9charID"}]</s>
// Detection marker:   has [INST] but NOT [SYSTEM_PROMPT] (distinguishes from Ministral 3)
static common_chat_params common_chat_params_init_mistral_instruct_v3(
    const common_chat_template &          tmpl,
    const autoparser::generation_params & inputs) {
    common_chat_params data;

    data.prompt            = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format            = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.supports_thinking = false;
    data.preserved_tokens  = {
        "[INST]",
        "[/INST]",
        "[TOOL_CALLS]",
        "[AVAILABLE_TOOLS]",
        "[/AVAILABLE_TOOLS]",
    };

    auto has_tools       = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    // Tool calls are emitted as:
    //   [TOOL_CALLS][{"name":"fn","arguments":{...},"id":"XXXXXXXXX"}]</s>
    // The JSON array is wrapped in "[...]" and terminated by the EOS token.
    const std::string TOOL_CALLS_START = "[TOOL_CALLS]";
    const std::string EOS              = tmpl.eos_token();

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
            // Parse optional content before tool calls, then the tool-call JSON array.
            auto tool_calls = p.standard_json_tools(
                TOOL_CALLS_START, EOS,
                inputs.tools, inputs.parallel_tool_calls,
                /* force_tool_calls = */ inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED,
                /* name_key = */ "name",
                /* args_key = */ "arguments",
                /* array_wrapped = */ true,
                /* function_is_key = */ false,
                /* call_id_key = */ "id",
                /* gen_call_id_key = */ "",
                /* parameters_order = */ {"name", "arguments", "id"});

            return p.prefix(inputs.generation_prompt) +
                   (p.content(p.until(TOOL_CALLS_START)) << tool_calls);
        }

        // Content-only path (no tools or tool_choice == NONE)
        include_grammar = false;
        return p.prefix(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;

        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto         schema   = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, TOOL_CALLS_START }
