static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Use the Jinja template directly: it prepends the system message into the first [INST] turn,
    // adds BOS, and appends </s> after every assistant turn.
    data.prompt = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto has_tools       = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto generation_prompt = p.prefix(inputs.generation_prompt);

        // Tool call parser — Nemo format: [TOOL_CALLS][{"name":…,"arguments":{…},"id":"…"}]</s>
        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
            auto tool_calls = p.standard_json_tools(
                "[TOOL_CALLS]", tmpl.eos_token(), inputs.tools,
                inputs.parallel_tool_calls,
                inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED,
                /* name_key        */ "name",
                /* args_key        */ "arguments",
                /* array_wrapped   */ true,
                /* function_is_key */ false,
                /* call_id_key     */ "id",
                /* gen_call_id_key */ "",
                /* params_order    */ {});
            return generation_prompt + p.content(p.until("[TOOL_CALLS]")) + tool_calls;
        }

        // Content-only parser
        include_grammar = false;
        return generation_prompt + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;

        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto         schema   = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    return data;
}

